// Interface — extensível e declarativa
interface User {
  id: number;
  name: string;
  email?: string; // optional
}

interface AdminUser extends User {
  role: 'admin' | 'superadmin';
}

// Type alias — mais flexível
type UserId = number;
type Response<T> = { data: T; error: string | null };
type Status = 'idle' | 'loading' | 'success' | 'error';

// Ambos funcionam para props React
interface ButtonProps { label: string; onClick: () => void; }
type ButtonProps2 = { label: string; onClick: () => void; };

// Função genérica simples
function first<T>(arr: T[]): T | undefined {
  return arr[0];
}
const n = first([1, 2, 3]);     // n é number
const s = first(['a', 'b']);    // s é string

// Com restrição
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}
const user = { id: 1, name: 'Ana' };
const id = getProperty(user, 'id');   // number ✅
// getProperty(user, 'age');          // ❌ Erro — 'age' não existe

// Tipo genérico
interface ApiResponse<T> {
  data: T;
  status: number;
  error: string | null;
}

interface User {
  id: number;
  name: string;
  email: string;
  password: string;
}

// Partial: todas as props opcionais
type UserUpdate = Partial<User>;  // { id?: number; name?: string; ... }

// Pick: seleciona props específicas
type UserPublic = Pick<User, 'id' | 'name'>;

// Omit: remove props
type UserWithoutPassword = Omit<User, 'password'>;

// Record: mapa de chaves para valores
type UserMap = Record<number, User>;

// ReturnType: extrai tipo de retorno de uma função
type FetchResult = ReturnType<typeof fetch>;  // Promise<Response>

// Readonly: todas as props read-only
const config: Readonly<{ port: number }> = { port: 8080 };

const COLORS = {
  primary: '#0ea5e9',
  secondary: '#f97316',
  accent: '#8b5cf6',
} as const;

// typeof extrai o tipo do objeto
type Colors = typeof COLORS;  // { primary: '...'; secondary: '...'; accent: '...' }

// keyof extrai as chaves
type ColorKey = keyof Colors;  // 'primary' | 'secondary' | 'accent'

// Função tipada com as chaves reais
function getColor(key: ColorKey): string {
  return COLORS[key];
}
getColor('primary');   // ✅
getColor('red');       // ❌ Erro de compilação
